import type {
    ClientLogDevicesResponse,
    CreateStoryBody,
    CreateStoryResponse,
    LogsResponse,
    LogLevel,
    PatchStoryBody,
    ProjectDashboardData,
    ProjectGitLogResponse,
    ProjectSummaryData,
    ProjectStoriesResponse,
    StoryDraftResponse,
    StoryResponse,
} from '@motivation/shared';
import { API_URL } from '../config.js';
import { apiError } from './http.js';
import { createComponentLogger } from '../utils/component-logger.js';

const log = createComponentLogger('projects-service');

export class ProjectsService {
    static async fetchMotivationSummary(): Promise<ProjectSummaryData> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/summary`);
        if (!response.ok) {
            throw await apiError(response, 'Failed to fetch motivation summary');
        }
        return response.json();
    }

    static async fetchMotivationDashboard(): Promise<ProjectDashboardData> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation`);
        if (!response.ok) {
            throw await apiError(response, 'Failed to fetch motivation dashboard');
        }
        return response.json();
    }

    static async fetchMotivationStories(): Promise<ProjectStoriesResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories`);
        if (!response.ok) {
            throw await apiError(response, 'Failed to fetch motivation stories');
        }
        return response.json();
    }

    static async fetchMotivationGitLog(): Promise<ProjectGitLogResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/git-log`);
        if (!response.ok) {
            throw await apiError(response, 'Failed to fetch motivation git log');
        }
        return response.json();
    }

    static async fetchMotivationLogs(params?: { date?: string; level?: LogLevel[]; search?: string; limit?: number; offset?: number }): Promise<LogsResponse> {
        const query = new URLSearchParams();
        if (params?.date) query.set('date', params.date);
        if (params?.level?.length) query.set('level', params.level.join(','));
        if (params?.search) query.set('search', params.search);
        if (params?.limit != null) query.set('limit', String(params.limit));
        if (params?.offset != null) query.set('offset', String(params.offset));
        const qs = query.toString();
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/logs${qs ? `?${qs}` : ''}`);
        if (!response.ok) {
            throw await apiError(response, 'Failed to fetch logs');
        }
        return response.json();
    }

    static async fetchClientLogDevices(): Promise<ClientLogDevicesResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/client-logs/devices`);
        if (!response.ok) {
            throw await apiError(response, 'Failed to fetch client log devices');
        }
        return response.json();
    }

    static async fetchStory(id: string): Promise<StoryResponse> {
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories/${encodeURIComponent(id)}`);
        if (!response.ok) throw await apiError(response, `Failed to fetch story ${id}`);
        return response.json();
    }

    static async createStory(body: CreateStoryBody): Promise<CreateStoryResponse> {
        log.info('POST /motivation/stories', { title: body.title, sectionsCount: Object.keys(body.sections ?? {}).length, destination: body.destination });
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        if (!response.ok) throw await apiError(response, 'Failed to create story');
        return response.json();
    }

    static async draftStoryFromNotes(notes: string): Promise<StoryDraftResponse> {
        log.info('POST /motivation/stories/draft-from-notes', { notesLength: notes.length });
        // Ollama structuring can take up to ~60s (matches OLLAMA_STRUCTURING_TIMEOUT_MS).
        // The service worker's networkFirstApi otherwise aborts at 15s and falls back to the
        // offline proxy, which has no projects handlers and would return a misleading
        // "Offline route not found" 404. X-Manual-AbortSignal disables the SW timeout and
        // hands timeout control to the AbortController below.
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 90_000);
        try {
            const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories/draft-from-notes`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'X-Manual-AbortSignal': 'true' },
                body: JSON.stringify({ notes }),
                signal: controller.signal,
            });
            log.debug('draft-from-notes response', { status: response.status });
            if (!response.ok) throw await apiError(response, 'Failed to draft story from notes');
            return response.json();
        } finally {
            clearTimeout(timeoutId);
        }
    }

    static async patchStory(id: string, body: PatchStoryBody): Promise<StoryResponse> {
        log.info('PATCH /motivation/stories/:id', { id, titleChanged: body.title !== undefined, sectionKeys: Object.keys(body.sections ?? {}) });
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/stories/${encodeURIComponent(id)}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        if (!response.ok) throw await apiError(response, `Failed to patch story ${id}`);
        return response.json();
    }

    static async fetchClientLogs(params: {
        device: string;
        date?: string;
        level?: LogLevel[];
        search?: string;
        limit?: number;
        offset?: number;
    }): Promise<LogsResponse> {
        const query = new URLSearchParams();
        query.set('device', params.device);
        if (params.date) query.set('date', params.date);
        if (params.level?.length) query.set('level', params.level.join(','));
        if (params.search) query.set('search', params.search);
        if (params.limit != null) query.set('limit', String(params.limit));
        if (params.offset != null) query.set('offset', String(params.offset));
        const response = await fetch(`${API_URL}/api/sections/projects/motivation/client-logs?${query.toString()}`);
        if (!response.ok) {
            throw await apiError(response, 'Failed to fetch client logs');
        }
        return response.json();
    }
}
